/**
 * MMS Authentication Service
 *
 * Handles user authentication, JWT token management, and session lifecycle.
 * Uses Bun's native password hashing and Hono's JWT helper.
 *
 * Security features:
 * - bcrypt-compatible password hashing (Bun.password)
 * - JWT access tokens with short expiry (1 hour)
 * - Refresh tokens with longer expiry (7 days)
 * - Session tracking for audit trail
 * - Account lockout after failed attempts
 * - Rate limiting support via failed_login_attempts
 *
 * @see specs/005-api.md Section 5.2 (Authentication Endpoints)
 */

import { eq, and, lt } from 'drizzle-orm';
import { sign, verify, decode } from 'hono/jwt';
import type { JWTPayload } from 'hono/utils/jwt/types';
import { BaseService } from '../lib/services/base';
import { users, sessions } from '../lib/db/schema';
import {
  AuthenticationError,
  TokenExpiredError,
  InvalidTokenError,
} from '../lib/errors';
import { randomUUID } from 'crypto';

// =============================================================================
// Constants
// =============================================================================

const ACCESS_TOKEN_EXPIRY_SECONDS = 3600; // 1 hour
const REFRESH_TOKEN_EXPIRY_SECONDS = 7 * 24 * 3600; // 7 days
const MAX_FAILED_ATTEMPTS = 5;
const LOCKOUT_DURATION_MINUTES = 30;

/** JWT signing algorithm */
const JWT_ALGORITHM = 'HS256' as const;

/**
 * JWT secret - in production, this should come from environment variables
 * or a secrets manager. Using a placeholder that MUST be overridden.
 */
const JWT_SECRET = process.env.JWT_SECRET || 'mms-development-secret-change-in-production';
const REFRESH_TOKEN_SECRET = process.env.REFRESH_TOKEN_SECRET || 'mms-refresh-secret-change-in-production';

// =============================================================================
// Types
// =============================================================================

/** User with role details for authentication response */
export interface AuthenticatedUser {
  id: string;
  email: string;
  displayName: string | null;
  firstName: string | null;
  lastName: string | null;
  roles: string[];
  primaryDepotId: string | null;
}

/** Login request */
export interface LoginRequest {
  email: string;
  password: string;
  ipAddress?: string;
  userAgent?: string;
}

/** Login response */
export interface LoginResponse {
  accessToken: string;
  refreshToken: string;
  expiresIn: number;
  user: AuthenticatedUser;
}

/** Token refresh request */
export interface RefreshRequest {
  refreshToken: string;
  ipAddress?: string;
  userAgent?: string;
}

/** Token refresh response */
export interface RefreshResponse {
  accessToken: string;
  refreshToken: string;
  expiresIn: number;
}

/** JWT payload structure - compatible with Hono's JWTPayload */
export interface JwtPayload extends JWTPayload {
  sub: string;
  email: string;
  roles: string[];
  depotId: string | null;
  sessionId: string;
  iat: number;
  exp: number;
}

/** Refresh token payload - compatible with Hono's JWTPayload */
export interface RefreshTokenPayload extends JWTPayload {
  sub: string;
  sessionId: string;
  type: 'refresh';
  iat: number;
  exp: number;
}

/** Session data */
export interface SessionData {
  userId: string;
  sessionId: string;
  email: string;
  roles: string[];
  depotId: string | null;
}

// =============================================================================
// Auth Service
// =============================================================================

export class AuthService extends BaseService {
  constructor() {
    super({ name: 'auth-service', version: '1.0.0' });
  }

  /**
   * Authenticate user with email and password
   */
  async login(request: LoginRequest): Promise<LoginResponse> {
    return this.traced('login', async (span) => {
      span.setAttribute('auth.email', request.email);

      // Find user by email
      const user = await this.db.query.users.findFirst({
        where: eq(users.email, request.email.toLowerCase()),
      });

      if (!user) {
        this.log.warn({ email: request.email }, 'Login attempt for non-existent user');
        throw new AuthenticationError('Invalid email or password');
      }

      // Check if account is locked
      if (user.lockedUntil && new Date(user.lockedUntil) > new Date()) {
        const remainingMinutes = Math.ceil(
          (new Date(user.lockedUntil).getTime() - Date.now()) / (1000 * 60)
        );
        this.log.warn({ userId: user.id, remainingMinutes }, 'Login attempt on locked account');
        throw new AuthenticationError(
          `Account is locked. Please try again in ${remainingMinutes} minutes.`
        );
      }

      // Check if user is active
      if (!user.isActive) {
        this.log.warn({ userId: user.id }, 'Login attempt on inactive account');
        throw new AuthenticationError('Account is disabled. Please contact an administrator.');
      }

      // Verify password using Bun's native password hashing
      const isValidPassword = await Bun.password.verify(request.password, user.passwordHash);

      if (!isValidPassword) {
        // Increment failed attempts
        const newFailedAttempts = (user.failedLoginAttempts || 0) + 1;
        const updates: Record<string, unknown> = {
          failedLoginAttempts: newFailedAttempts,
          updatedAt: new Date(),
        };

        // Lock account if max attempts exceeded
        if (newFailedAttempts >= MAX_FAILED_ATTEMPTS) {
          updates.lockedUntil = new Date(Date.now() + LOCKOUT_DURATION_MINUTES * 60 * 1000);
          this.log.warn({ userId: user.id, attempts: newFailedAttempts }, 'Account locked due to failed attempts');
        }

        await this.db.update(users).set(updates).where(eq(users.id, user.id));

        throw new AuthenticationError('Invalid email or password');
      }

      // Reset failed attempts on successful login
      await this.db
        .update(users)
        .set({
          failedLoginAttempts: 0,
          lockedUntil: null,
          lastLoginAt: new Date(),
          updatedAt: new Date(),
        })
        .where(eq(users.id, user.id));

      // Create session
      const sessionId = randomUUID();
      const now = new Date();
      const refreshTokenExpiry = new Date(now.getTime() + REFRESH_TOKEN_EXPIRY_SECONDS * 1000);

      // Generate tokens
      const accessToken = await this.generateAccessToken({
        userId: user.id,
        email: user.email,
        roles: user.roleIds || [],
        depotId: user.primaryDepotId,
        sessionId,
      });

      const refreshToken = await this.generateRefreshToken({
        userId: user.id,
        sessionId,
      });

      // Hash refresh token for storage
      const tokenHash = await this.hashToken(refreshToken);

      // Store session in database
      await this.db.insert(sessions).values({
        id: sessionId,
        userId: user.id,
        tokenHash,
        expiresAt: refreshTokenExpiry,
        lastActivityAt: now,
        ipAddress: request.ipAddress,
        userAgent: request.userAgent,
      });

      this.log.info({ userId: user.id, sessionId }, 'User logged in successfully');

      return {
        accessToken,
        refreshToken,
        expiresIn: ACCESS_TOKEN_EXPIRY_SECONDS,
        user: {
          id: user.id,
          email: user.email,
          displayName: user.displayName,
          firstName: user.firstName,
          lastName: user.lastName,
          roles: user.roleIds || [],
          primaryDepotId: user.primaryDepotId,
        },
      };
    });
  }

  /**
   * Refresh access token using refresh token
   */
  async refreshToken(request: RefreshRequest): Promise<RefreshResponse> {
    return this.traced('refreshToken', async (span) => {
      // Verify and decode refresh token
      let payload: RefreshTokenPayload;
      try {
        const verified = await verify(request.refreshToken, REFRESH_TOKEN_SECRET, JWT_ALGORITHM);
        payload = verified as RefreshTokenPayload;
      } catch {
        throw new InvalidTokenError('Invalid refresh token');
      }

      if (payload.type !== 'refresh') {
        throw new InvalidTokenError('Invalid token type');
      }

      span.setAttribute('auth.session_id', payload.sessionId);

      // Find session
      const session = await this.db.query.sessions.findFirst({
        where: and(
          eq(sessions.id, payload.sessionId),
          eq(sessions.userId, payload.sub)
        ),
      });

      if (!session) {
        throw new InvalidTokenError('Session not found');
      }

      // Check if session is expired
      if (new Date(session.expiresAt) < new Date()) {
        await this.db.delete(sessions).where(eq(sessions.id, session.id));
        throw new TokenExpiredError('Session has expired');
      }

      // Verify token hash
      const isValidToken = await this.verifyTokenHash(request.refreshToken, session.tokenHash);
      if (!isValidToken) {
        throw new InvalidTokenError('Token mismatch');
      }

      // Get user
      const user = await this.db.query.users.findFirst({
        where: eq(users.id, session.userId),
      });

      if (!user || !user.isActive) {
        throw new AuthenticationError('User account is not available');
      }

      // Generate new tokens
      const newSessionId = randomUUID();
      const now = new Date();
      const newRefreshTokenExpiry = new Date(now.getTime() + REFRESH_TOKEN_EXPIRY_SECONDS * 1000);

      const newAccessToken = await this.generateAccessToken({
        userId: user.id,
        email: user.email,
        roles: user.roleIds || [],
        depotId: user.primaryDepotId,
        sessionId: newSessionId,
      });

      const newRefreshToken = await this.generateRefreshToken({
        userId: user.id,
        sessionId: newSessionId,
      });

      // Hash new refresh token
      const newTokenHash = await this.hashToken(newRefreshToken);

      // Delete old session and create new one (token rotation)
      await this.db.delete(sessions).where(eq(sessions.id, session.id));

      await this.db.insert(sessions).values({
        id: newSessionId,
        userId: user.id,
        tokenHash: newTokenHash,
        expiresAt: newRefreshTokenExpiry,
        lastActivityAt: now,
        ipAddress: request.ipAddress,
        userAgent: request.userAgent,
      });

      this.log.info({ userId: user.id, oldSessionId: session.id, newSessionId }, 'Token refreshed');

      return {
        accessToken: newAccessToken,
        refreshToken: newRefreshToken,
        expiresIn: ACCESS_TOKEN_EXPIRY_SECONDS,
      };
    });
  }

  /**
   * Logout and invalidate session
   */
  async logout(accessToken: string): Promise<void> {
    return this.traced('logout', async (span) => {
      // Decode access token to get session ID
      let payload: JwtPayload;
      try {
        const verified = await verify(accessToken, JWT_SECRET, JWT_ALGORITHM);
        payload = verified as JwtPayload;
      } catch {
        // Token might be expired but we still want to invalidate the session
        try {
          const decoded = decode(accessToken);
          if (decoded && decoded.payload && typeof decoded.payload === 'object') {
            payload = decoded.payload as JwtPayload;
          } else {
            throw new InvalidTokenError('Cannot decode token');
          }
        } catch {
          throw new InvalidTokenError('Invalid access token');
        }
      }

      span.setAttribute('auth.session_id', payload.sessionId);

      // Delete session
      const result = await this.db
        .delete(sessions)
        .where(eq(sessions.id, payload.sessionId))
        .returning({ id: sessions.id });

      if (result.length > 0) {
        this.log.info({ userId: payload.sub, sessionId: payload.sessionId }, 'User logged out');
      }
    });
  }

  /**
   * Verify access token and return session data
   */
  async verifyAccessToken(token: string): Promise<SessionData> {
    return this.traced('verifyAccessToken', async (span) => {
      let payload: JwtPayload;
      try {
        const verified = await verify(token, JWT_SECRET, JWT_ALGORITHM);
        payload = verified as JwtPayload;
      } catch (error) {
        if (error instanceof Error && error.message.includes('expired')) {
          throw new TokenExpiredError('Access token has expired');
        }
        throw new InvalidTokenError('Invalid access token');
      }

      span.setAttribute('auth.user_id', payload.sub);
      span.setAttribute('auth.session_id', payload.sessionId);

      // Verify session exists
      const session = await this.db.query.sessions.findFirst({
        where: eq(sessions.id, payload.sessionId),
      });

      if (!session) {
        throw new InvalidTokenError('Session not found');
      }

      // Update last activity
      await this.db
        .update(sessions)
        .set({ lastActivityAt: new Date() })
        .where(eq(sessions.id, payload.sessionId));

      return {
        userId: payload.sub,
        sessionId: payload.sessionId,
        email: payload.email,
        roles: payload.roles,
        depotId: payload.depotId,
      };
    });
  }

  /**
   * Get user by ID
   */
  async getUserById(userId: string): Promise<AuthenticatedUser | null> {
    return this.traced('getUserById', async (span) => {
      span.setAttribute('auth.user_id', userId);

      const user = await this.db.query.users.findFirst({
        where: eq(users.id, userId),
      });

      if (!user) {
        return null;
      }

      return {
        id: user.id,
        email: user.email,
        displayName: user.displayName,
        firstName: user.firstName,
        lastName: user.lastName,
        roles: user.roleIds || [],
        primaryDepotId: user.primaryDepotId,
      };
    });
  }

  /**
   * Hash a password for storage
   */
  async hashPassword(password: string): Promise<string> {
    return Bun.password.hash(password, {
      algorithm: 'bcrypt',
      cost: 10,
    });
  }

  /**
   * Clean up expired sessions
   */
  async cleanupExpiredSessions(): Promise<number> {
    return this.traced('cleanupExpiredSessions', async () => {
      const result = await this.db
        .delete(sessions)
        .where(lt(sessions.expiresAt, new Date()))
        .returning({ id: sessions.id });

      this.log.info({ count: result.length }, 'Cleaned up expired sessions');
      return result.length;
    });
  }

  // ===========================================================================
  // Private Helpers
  // ===========================================================================

  private async generateAccessToken(data: {
    userId: string;
    email: string;
    roles: string[];
    depotId: string | null;
    sessionId: string;
  }): Promise<string> {
    const now = Math.floor(Date.now() / 1000);
    const payload: JwtPayload = {
      sub: data.userId,
      email: data.email,
      roles: data.roles,
      depotId: data.depotId,
      sessionId: data.sessionId,
      iat: now,
      exp: now + ACCESS_TOKEN_EXPIRY_SECONDS,
    };

    return sign(payload, JWT_SECRET, JWT_ALGORITHM);
  }

  private async generateRefreshToken(data: {
    userId: string;
    sessionId: string;
  }): Promise<string> {
    const now = Math.floor(Date.now() / 1000);
    const payload: RefreshTokenPayload = {
      sub: data.userId,
      sessionId: data.sessionId,
      type: 'refresh',
      iat: now,
      exp: now + REFRESH_TOKEN_EXPIRY_SECONDS,
    };

    return sign(payload, REFRESH_TOKEN_SECRET, JWT_ALGORITHM);
  }

  private async hashToken(token: string): Promise<string> {
    const hasher = new Bun.CryptoHasher('sha256');
    hasher.update(token);
    return hasher.digest('hex');
  }

  private async verifyTokenHash(token: string, hash: string): Promise<boolean> {
    const computedHash = await this.hashToken(token);
    return computedHash === hash;
  }
}

// =============================================================================
// Singleton Instance
// =============================================================================

let authServiceInstance: AuthService | null = null;

/**
 * Get the singleton AuthService instance
 */
export function getAuthService(): AuthService {
  if (!authServiceInstance) {
    authServiceInstance = new AuthService();
  }
  return authServiceInstance;
}

