     1→/**
     2→ * MMS Costing Service
     3→ *
     4→ * Calculates TCO (Total Cost of Ownership) projections, tracks variance against budget,
     5→ * and provides cost impact analysis for schedule adjustments.
     6→ *
     7→ * Key responsibilities:
     8→ * - Calculate individual PM costs (labor + materials + overhead)
     9→ * - Project 12-year TCO with inflation and NPV calculations
    10→ * - Track budget vs. actual cost variance
    11→ * - Support depot-level and global cost analysis
    12→ *
    13→ * Cost calculation components:
    14→ * - Labor: Hours × shop rate with shift multipliers
    15→ * - Materials: Part costs from PM material requirements
    16→ * - Overhead: 18% of direct costs (industry standard)
    17→ *
    18→ * Financial parameters (12-year contract):
    19→ * - Inflation: 3% annually
    20→ * - Discount rate: 5% for NPV calculations
    21→ * - Variance tolerance: 10% before flagging as over-budget
    22→ *
    23→ * @see specs/004-domain-services.md Section 4.10
    24→ */
    25→
    26→import { eq, and, gte, lte, isNull, sql, desc } from 'drizzle-orm';
    27→import { BaseService, MmsAttributes } from '../lib/services/base';
    28→import {
    29→  pmSchedule,
    30→  pmTypes,
    31→  pmMaterialRequirements,
    32→  laborRates,
    33→  materialCosts,
    34→  costBaselines,
    35→} from '../lib/db/schema';
    36→import { NotFoundError } from '../lib/errors';
    37→import { costingMetrics } from '../lib/metrics';
    38→
    39→/** PM schedule record type (inferred from schema) */
    40→type PmScheduleRecord = typeof pmSchedule.$inferSelect;
    41→
    42→/** PM type record (inferred from schema) */
    43→type PmTypeRecord = typeof pmTypes.$inferSelect;
    44→
    45→// =============================================================================
    46→// Constants
    47→// =============================================================================
    48→
    49→/** Overhead rate applied to direct costs (labor + materials) */
    50→export const OVERHEAD_RATE = 0.18;
    51→
    52→/** Annual inflation rate for TCO projections */
    53→export const INFLATION_RATE = 0.03;
    54→
    55→/** Discount rate for NPV calculations */
    56→export const DISCOUNT_RATE = 0.05;
    57→
    58→/** Default TCO projection horizon in years (contract period) */
    59→export const DEFAULT_HORIZON_YEARS = 12;
    60→
    61→/** Budget variance tolerance before flagging as over-budget */
    62→export const VARIANCE_TOLERANCE = 0.10;
    63→
    64→/** Overtime multiplier for night shift (default if not in labor rates) */
    65→export const DEFAULT_OVERTIME_MULTIPLIER = 1.35;
    66→
    67→/** Weekend multiplier (default if not in labor rates) */
    68→export const DEFAULT_WEEKEND_MULTIPLIER = 1.5;
    69→
    70→/** Default shop rate if not configured (SGD/hour) */
    71→export const DEFAULT_SHOP_RATE = 85.0;
    72→
    73→// =============================================================================
    74→// Types
    75→// =============================================================================
    76→
    77→/** Detailed cost breakdown for a PM */
    78→export interface CostBreakdown {
    79→  laborCost: number;
    80→  overtimeCost: number;
    81→  materialCost: number;
    82→  contractorCost: number;
    83→  overheadCost: number;
    84→  totalCost: number;
    85→}
    86→
    87→/** Yearly cost projection for TCO */
    88→export interface YearlyCost {
    89→  fiscalYear: number;
    90→  laborCost: number;
    91→  materialCost: number;
    92→  totalCost: number;
    93→  pmCount: number;
    94→  inflationFactor: number;
    95→}
    96→
    97→/** TCO projection summary */
    98→export interface TCOSummary {
    99→  totalLaborCost: number;
   100→  totalMaterialCost: number;
   101→  totalCost: number;
   102→  totalPMCount: number;
   103→  npv: number;
   104→  avgAnnualCost: number;
   105→}
   106→
   107→/** Full TCO projection result */
   108→export interface TCOProjection {
   109→  projections: YearlyCost[];
   110→  summary: TCOSummary;
   111→  horizonYears: number;
   112→  calculatedAt: Date;
   113→}
   114→
   115→/** Budget figures for variance calculation */
   116→export interface BudgetFigures {
   117→  labor: number;
