   717→    budgetLaborCost: number;
   718→    budgetMaterialCost: number;
   719→    budgetLaborHours?: number;
   720→  }): Promise<typeof costBaselines.$inferSelect> {
   721→    return this.traced('upsertCostBaseline', async (span) => {
   722→      span.setAttribute('baseline.fiscal_year', baseline.fiscalYear);
   723→      if (baseline.depotId) {
