   171→/** Inference result for batch operations */
   172→export interface InferenceResult {
   173→  created: number;
   174→  skipped: number;
   175→  errors: Array<{ trainId: string; pmTypeId: string; error: string }>;
   176→  assumptions: AssumptionWithDetails[];
   177→}
