   991→          trainId: train.id,
   992→          pmTypeId: knownPmType.id,
   993→          error: error instanceof Error ? error.message : String(error),
   994→        });
   995→      }
   996→
   997→      this.log.info(
   998→        {
   999→          trainId: train.id,
  1000→          knownPmCode: request.knownPmTypeCode,
  1001→          created: result.created,
  1002→          skipped: result.skipped,
  1003→          errors: result.errors.length,
  1004→        },
  1005→        'Completed higher PM inference'
  1006→      );
  1007→
  1008→      return result;
  1009→    });
  1010→  }
  1011→
  1012→  /**
  1013→   * Get assumptions for a train (useful for PM scheduler integration)
  1014→   */
  1015→  async getAssumptionsForTrain(trainId: string): Promise<AssumptionWithDetails[]> {
  1016→    return this.traced('getAssumptionsForTrain', async (span) => {
  1017→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
  1018→
  1019→      const result = await this.listAssumptions({ trainId }, { pageSize: 100 });
  1020→      return result.items;
  1021→    });
  1022→  }
  1023→
  1024→  /**
  1025→   * Get applied assumptions for PM baseline calculation
  1026→   */
  1027→  async getAppliedAssumptions(trainId?: string): Promise<AssumptionWithDetails[]> {
  1028→    return this.traced('getAppliedAssumptions', async (span) => {
  1029→      if (trainId) {
  1030→        span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
  1031→      }
  1032→
  1033→      const result = await this.listAssumptions(
  1034→        {
  1035→          trainId,
  1036→          applied: true,
  1037→        },
  1038→        { pageSize: 1000 }
  1039→      );
  1040→
  1041→      return result.items;
  1042→    });
  1043→  }
  1044→
  1045→  // ===========================================================================
  1046→  // Private Helpers
  1047→  // ===========================================================================
  1048→
  1049→  /**
  1050→   * Map database result to AssumptionWithDetails
  1051→   */
  1052→  private mapToAssumptionWithDetails(
  1053→    assumption: PmBaselineAssumption & {
  1054→      train?: Train | null;
  1055→      pmType?: PmType | null;
  1056→      reviewedByUser?: { id: string; email: string } | null;
  1057→      appliedByUser?: { id: string; email: string } | null;
  1058→    }
  1059→  ): AssumptionWithDetails {
  1060→    // Determine review status
  1061→    let reviewStatus: ReviewStatus;
  1062→    if (assumption.appliedAt) {
  1063→      reviewStatus = 'APPLIED';
  1064→    } else if (assumption.reviewedAt) {
  1065→      if (assumption.reviewNotes?.startsWith('REJECTED:')) {
  1066→        reviewStatus = 'REJECTED';
  1067→      } else {
  1068→        reviewStatus = 'REVIEWED';
  1069→      }
  1070→    } else {
  1071→      reviewStatus = 'PENDING_REVIEW';
  1072→    }
  1073→
  1074→    return {
  1075→      ...assumption,
  1076→      train: assumption.train
  1077→        ? {
  1078→            id: assumption.train.id,
  1079→            trainNumber: assumption.train.trainNumber,
