  1100→            intervalMonths: null,
  1101→          } as Pick<PmType, 'id' | 'pmCode' | 'intervalKm' | 'intervalMonths'>),
  1102→      reviewedByUser: assumption.reviewedByUser ?? null,
  1103→      appliedByUser: assumption.appliedByUser ?? null,
